   250	                    //   mapping x__: bool => field;
   251	                    //   ...
   252	                    //   _mapping_set(x__, false, 5field);
   253	                    let set_expr: Expression = IntrinsicExpression {
   254	                        name: sym::_mapping_set,
   255	                        type_parameters: vec![],
   256	                        input_types: vec![],
   257	                        return_types: vec![],
   258	                        arguments: vec![mapping_expr, false_literal, new_value],
   259	                        span,
   260	                        id: id(),
   261	                    }
   262	                    .into();
