   280	    fn reconstruct_block(&mut self, block: Block) -> (Block, Self::AdditionalOutput) {
   281	        let mut statements = Vec::with_capacity(block.statements.len());
   282	
   283	        // Flatten each statement, accumulating any new statements produced.
   284	        for statement in block.statements {
   285	            let (reconstructed_statement, additional_statements) = self.reconstruct_statement(statement);
   286	            statements.extend(additional_statements);
   287	            statements.push(reconstructed_statement);
   288	        }
   289	
   290	        (Block { span: block.span, statements, id: self.state.node_builder.next_id() }, Default::default())
   291	    }
