   293	    fn reconstruct_conditional(&mut self, input: leo_ast::ConditionalStatement) -> (Statement, Self::AdditionalOutput) {
   294	        let (condition, mut statements) = self.reconstruct_expression(input.condition, &());
   295	        let (then, statements2) = self.reconstruct_block(input.then);
   296	        statements.extend(statements2);
   297	        let otherwise = input.otherwise.map(|oth| {
   298	            let (expr, statements3) = self.reconstruct_statement(*oth);
   299	            statements.extend(statements3);
   300	            Box::new(expr)
   301	        });
   302	        (ConditionalStatement { condition, then, otherwise, ..input }.into(), statements)
   303	    }
