   305	    fn reconstruct_const(&mut self, input: ConstDeclaration) -> (Statement, Self::AdditionalOutput) {
   306	        let (type_expr, type_statements) = self.reconstruct_type(input.type_);
   307	        let (value_expr, value_statements) = self.reconstruct_expression(input.value, &Default::default());
   308	
   309	        let mut statements = Vec::new();
   310	        statements.extend(type_statements);
   311	        statements.extend(value_statements);
   312	
   313	        (ConstDeclaration { type_: type_expr, value: value_expr, ..input }.into(), statements)
   314	    }
