   325	    fn reconstruct_expression_statement(&mut self, input: ExpressionStatement) -> (Statement, Self::AdditionalOutput) {
   326	        let (reconstructed_expression, statements) = self.reconstruct_expression(input.expression, &Default::default());
   327	        if !matches!(
   328	            reconstructed_expression,
   329	            Expression::Call(_) | Expression::DynamicCall(_) | Expression::Intrinsic(_)
   330	        ) {
   331	            (
   332	                ExpressionStatement {
   333	                    expression: Expression::Unit(UnitExpression {
   334	                        span: Span::default(),
   335	                        id: self.state.node_builder.next_id(),
   336	                    }),
   337	                    ..input
   338	                }
   339	                .into(),
   340	                statements,
   341	            )
   342	        } else {
   343	            (ExpressionStatement { expression: reconstructed_expression, ..input }.into(), statements)
   344	        }
   345	    }
